// Normaliza um CID: letra + 2 dígitos + (1-2 dígitos opcionais).
function norm(s) {
  if (!s) return '';
  const m = String(s).toUpperCase().match(/([A-Z])\s*(\d{2})\s*\.?\s*(\d{1,2})?/);
  if (!m) return '';
  return m[1] + m[2] + (m[3] || '');
}

const exactMap = {};
const catAgg = {};
for (const e of ENTRIES) {
  const k = norm(e.cid);
  if (k) exactMap[k] = e;
  const c = k.slice(0, 3);
  if (c) {
    if (!catAgg[c]) catAgg[c] = { soma: 0, n: 0, ex: null };
    if (typeof e.taxa === 'number') { catAgg[c].soma += e.taxa; catAgg[c].n += 1; }
    if (!catAgg[c].ex) catAgg[c].ex = e;
  }
}
const catMap = {};
for (const c of Object.keys(catAgg)) {
  const a = catAgg[c];
  const taxa = a.n ? a.soma / a.n : null;
  catMap[c] = Object.assign({}, a.ex, {
    cid: c, taxa,
    classe: taxa == null ? 'Média' : (taxa >= 90 ? 'Muito Alta' : (taxa >= 80 ? 'Alta' : (taxa >= 70 ? 'Média' : (taxa >= 50 ? 'Baixa' : 'Muito Baixa')))),
  });
}

// Procura um CID (texto bruto da CAT) na base. Retorna o registro ou null.
function lookupCid(raw) {
  const k = norm(raw);
  if (!k) return null;
  if (exactMap[k]) return Object.assign({ match: 'exato' }, exactMap[k]);
  const k3 = k.slice(0, 3);
  if (exactMap[k3]) return Object.assign({ match: 'exato' }, exactMap[k3]);
  if (catMap[k3]) return Object.assign({ match: 'categoria' }, catMap[k3]);
  return null;
}

module.exports = { ENTRIES, lookupCid, norm };
